void bpnn_layerforward_ocl(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid,
                      int num_blocks) 
{
   int by, tx, ty;
   int index, index_in;
   float input_node[HEIGHT];
   float weight_matrix[HEIGHT * WIDTH];

   #pragma omp parallel for private(by, tx, ty, index, index_in, input_node, weight_matrix) schedule(static)
   for (int block_idx = 0; block_idx < num_blocks * HEIGHT; block_idx++) {
      by = block_idx / HEIGHT;
      ty = block_idx % HEIGHT;

      for (tx = 0; tx < WIDTH; tx++) {
         index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );  
         index_in = HEIGHT * by + ty + 1;

         if ( tx == 0 )
            input_node[ty] = input_cuda[index_in];

         weight_matrix[ty * WIDTH + tx] =  input_hidden_cuda[index];

         weight_matrix[ty * WIDTH + tx]= weight_matrix[ty * WIDTH + tx] * input_node[ty];

         for ( int i = 1 ; i <= HEIGHT ; i=i*2){
            int power_two = i; 
            if( ty % power_two == 0 )
               weight_matrix[ty * WIDTH + tx]= weight_matrix[ty * WIDTH + tx] + weight_matrix[(ty + power_two/2)* WIDTH + tx];
         }

         input_hidden_cuda[index] =  weight_matrix[ty * WIDTH + tx];

         if ( tx == 0 ) {
            hidden_partial_sum[by * hid + ty] = weight_matrix[tx* WIDTH + ty];
         }
      }
   }
}

void bpnn_adjust_weights_ocl( float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw,
                                        int num_blocks)   
{
   int by, tx, ty;
   int index, index_y, index_x;

   #pragma omp parallel for private(by, tx, ty, index, index_y, index_x) schedule(static)
   for (int block_idx = 0; block_idx < num_blocks * HEIGHT; block_idx++) {
      by = block_idx / HEIGHT;
      ty = block_idx % HEIGHT;

      for (tx = 0; tx < WIDTH; tx++) {
         index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );  
         index_y = HEIGHT * by + ty + 1;
         index_x = tx + 1;

         w[index] += ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
         oldw[index] = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));

         if (ty == 0 && by ==0){
            w[index_x] += ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
            oldw[index_x] = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
         }
      }
   }
}

int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
	int in, hid, out;
	float out_err, hid_err;
	float sum;
	float num_blocks;

	in = net->input_n;
	hid = net->hidden_n;
	out = net->output_n;

	float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
	float * partial_sum;

	num_blocks = in / BLOCK_SIZE;

	input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

	int m = 0;
	for (int k = 0; k <= in; k++) {
		for (int j = 0; j <= hid; j++) {
		input_weights_one_dim[m] = net->input_weights[k][j];
		input_weights_prev_one_dim[m] = net-> input_prev_weights[k][j];
	    m++;
		}
	}

	printf("Performing CPU computation\n");

    bpnn_layerforward_ocl(net->input_units, NULL, input_weights_one_dim, partial_sum, in, hid, num_blocks);

	for (int j = 1; j <= hid; j++) {
		sum = 0.0;
		for (int k = 0; k < num_blocks; k++) {
		sum += partial_sum[k * hid + j-1] ;
    }
		sum += net->input_weights[0][j];
		net-> hidden_units[j] = float(1.0 / (1.0 + exp(-sum)));
	}

	bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
	bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
	bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
	bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

    bpnn_adjust_weights_ocl(net->hidden_delta, hid, net->input_units, in, input_weights_one_dim, input_weights_prev_one_dim, num_blocks);

    for (int k = 0; k <= in; k++) {
        for (int j = 0; j <= hid; j++) {
            net->input_weights[k][j] = input_weights_one_dim[k * (hid + 1) + j];
            net->input_prev_weights[k][j] = input_weights_prev_one_dim[k * (hid + 1) + j];
        }
    }

	free(input_weights_prev_one_dim);
	free(partial_sum);
	free(input_weights_one_dim);

    return 0;
}

int setup(int argc, char** argv)
{
    int layer_size = -1;
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
            fprintf(stderr, "usage: backprop <-n num of input elements>\n");
            exit(0);
        }
        else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                layer_size = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

    if (layer_size % 16 != 0){
        fprintf(stderr, "The number of input points must be divided by 16\n");
        exit(0);
    }

    int seed = 7;
    bpnn_initialize(seed);

    BPNN *net;
    float out_err, hid_err;
    net = bpnn_create(layer_size, 16, 1); 
    printf("Input layer size : %d\n", layer_size);

    float *units;
    int nr, k, i;
    nr = layer_size;
    units = net->input_units;
    k = 1;
    for (i = 0; i < nr; i++) {
        units[k] = (float) rand()/RAND_MAX ;
        k++;
    }

    printf("Starting training kernel\n");
    bpnn_train_kernel(net, &out_err, &hid_err);
    bpnn_free(net);
    printf("\nFinish the training for one iteration\n");

    exit(0);
}

int main( int argc, char** argv)
{
	setup(argc, argv);
}
